import React, {useState} from "react";
export default (props) => {
	const [input1, onChangeInput1] = useState('');
	const [input2, onChangeInput2] = useState('');
	const [input3, onChangeInput3] = useState('');
	const [input4, onChangeInput4] = useState('');
	return (
		<div className="items-start bg-white">
			<div className="items-start bg-[#88BCF8] w-[1440px] rounded-[10px]">
				<div className="flex flex-col items-start bg-[#A2D3FF] w-[800px] pt-[78px] pb-5 mt-[120px] mb-[204px] mx-80 rounded-[10px]">
					<span className="text-black text-[32px] mb-8 ml-[317px]" >
						{"ĐĂNG KÝ"}
					</span>
					<input
						placeholder={"MSSV"}
						value={input1}
						onChange={(event)=>onChangeInput1(event.target.value)}
						className="text-black bg-[#F7FFFF] text-xl w-[493px] py-3 pl-[33px] pr-[66px] mb-[9px] mx-[153px] rounded-[10px] border-0"
					/>
					<input
						placeholder={"sdt"}
						value={input2}
						onChange={(event)=>onChangeInput2(event.target.value)}
						className="text-black bg-[#F7FFFF] text-xl w-[493px] py-[9px] pl-[33px] pr-[66px] mb-[9px] mx-[153px] rounded-[10px] border-0"
					/>
					<input
						placeholder={"Mk"}
						value={input3}
						onChange={(event)=>onChangeInput3(event.target.value)}
						className="text-black bg-[#F7FFFF] text-xl w-[493px] py-[11px] pl-[33px] pr-[66px] mb-[9px] mx-[153px] rounded-[10px] border-0"
					/>
					<input
						placeholder={"Xác thực mk"}
						value={input4}
						onChange={(event)=>onChangeInput4(event.target.value)}
						className="text-black bg-[#F7FFFF] text-xl w-[493px] py-5 pl-[33px] pr-[66px] mb-[65px] mx-[152px] rounded-[10px] border-0"
					/>
					<button className="flex flex-col items-start bg-[#F7FFFF] text-left py-[3px] mb-16 ml-[307px] rounded-[10px] border border-solid border-black"
						onClick={()=>alert("Pressed!")}>
						<span className="text-black text-2xl mx-1.5" >
							{"Hoàn tất rồi nhé"}
						</span>
                        <button
                             onClick={props.goToLogin}
                             className="text-blue-700 underline mt-2"
                                            >   
                                 Quay về đăng nhập
                    </button>

					</button>
					<span className="text-black text-xl ml-[74px]" >
						{"Đăng ký rồi thì phải...phải 123 zô!!"}
					</span>
				</div>
			</div>
		</div>
	)
}
